const mppx = Mppx.create({
  polyfill: false,
  fetch: gate.fetch,
  methods: [tempo.charge({ account })],
  onChallenge: gate.onChallenge,
});

const { fetch, getLast402, clearLast402 } = createCapture402Fetch(underlyingFetch);

async function onChallenge(challenge, _helpers) {
  const bundle = buildPaymentBundle({
    challenge,
    capture402: getLast402(),
  });

  if (onBundle) await onBundle(bundle);

  if (waitForTerms) {
    const terms = await waitForTerms(bundle);
    if (onTerms) await onTerms(bundle, terms);
  }

  return undefined;
}

return { fetch, getLast402, clearLast402, onChallenge };

export function createCapture402Fetch(underlying = globalThis.fetch) {
  let last = null;

  async function wrapped(input, init) {
    const requestUrl =
      typeof input === "string"
        ? input
        : input instanceof URL
          ? input.href
          : input.url;
    const res = await underlying(input, init);
    if (res.status === 402) {
      const headers = Object.fromEntries(res.headers.entries());
      last = {
        requestUrl,
        requestMethod: (init?.method ?? "GET").toUpperCase(),
        status: res.status,
        headers,
        wwwAuthenticate: res.headers.get("WWW-Authenticate"),
      };
    }
    return res;
  }

  return {
    fetch: wrapped,
    getLast402: () => last,
    clearLast402: () => { last = null; },
  };
}
